            for (i = [0 : holes_per_ring[r_idx] - 1]) {
                ang = 360 * i / holes_per_ring[r_idx];
                translate([ring_radii[r_idx]*cos(ang),
                           ring_radii[r_idx]*sin(ang), -0.1])
                    cylinder(d = hole_d, h = floor_h + 0.2);
