module c_pickup_rod() {
    // boss
    translate([0, 0, shank_l])
        difference() {
            cylinder(d = boss_d, h = boss_h);
            // wrench-flats
            for (sx = [-1, 1])
                translate([sx*(boss_d/2 - boss_flat_d),
                           -boss_flat_w/2, 2])
                    cube([boss_flat_d + 0.5, boss_flat_w, boss_h - 4]);
        }
    // shank
    cylinder(d = shank_d, h = shank_l + 0.5);
    // capillary tip (steps down)
    difference() {
        union() {
            translate([0, 0, -tip_l])
                cylinder(d = tip_d_outer, h = tip_l + 0.5);
            // small chamfer step at shank-to-tip junction for printability
            translate([0, 0, -1.0])
                cylinder(d1 = tip_d_outer, d2 = shank_d, h = 1.0);
        }
        // capillary bore
        translate([0, 0, -tip_l - 0.1])
            cylinder(d = tip_d_inner, h = tip_l + shank_l + boss_h + 1);
    }
}

module c_wiper_post() {
    // bed-mounted wiper post that strikes off the excess. Lives on the
    // 3018 bed offset from the powder cup; the gantry dips, lifts,
    // then drags the tip across the slot to wipe.
    translate([0, 60, 0]) {       // offset so it doesn't intersect the rod
        difference() {
            union() {
                translate([-wiper_w/2, -wiper_h/2, 0])
                    cube([wiper_w, wiper_h, wiper_post_h]);
                translate([-wiper_w/2 - 5, -wiper_h/2 - 2, 0])
                    cube([wiper_w + 10, wiper_h + 4, 3]);   // base flange
            }
            // slot the capillary tip drags through
            translate([-wiper_w/2 - 1, -wiper_slot_w/2,
                       wiper_post_h - tip_l + 1])
                cube([wiper_w + 2, wiper_slot_w, tip_l]);
            // M3 mounting holes
            for (sx = [-1, 1])
                translate([sx*(wiper_w/2 + 2), 0, -0.1])
                    cylinder(d = 3.4, h = 4);
        }
    }
}

c_pickup_rod();
c_wiper_post();


==== F_passive_auger.scad ====
// =====================================================================
// alternatives/F_passive_auger.scad — Passive auger via rack-and-pinion
// against a fixed pin (concept F).
// ---------------------------------------------------------------------
// A spindle-mounted vertical Archimedes auger inside a tube. The
// auger is keyed to a small printed pinion at the top; a *fixed*
// printed rack on the bed engages the pinion when the gantry rapids
// the assembly horizontally. The spindle does not have to rotate —
// linear gantry motion drives auger rotation passively.
//
// Heavily inspired by PR #16's Archimedes auger geometry, simplified
// to fit in a single ~80-line SCAD source.
// =====================================================================

$fa = 2; $fs = 0.4;

// --- Parameters (mm) -------------------------------------------------
boss_d        = 43;
boss_h        = 12;
tube_od       = 16;
tube_id       = 13;
tube_h        = 60;
pinion_d      = 18;
pinion_h      = 4;
n_teeth       = 14;
helix_pitch   = 12;
helix_r       = 5.5;
fin_t         = 1.6;
exit_d        = 2.5;

module f_pinion() {
    difference() {
        cylinder(d = pinion_d, h = pinion_h);
        for (i = [0 : n_teeth - 1])
            rotate([0, 0, 360*i/n_teeth + 360/(2*n_teeth)])
                translate([pinion_d/2 - 0.5, -0.6, -0.1])
                    cube([1.5, 1.2, pinion_h + 0.2]);
    }
}

module f_helix() {
    n_steps = 220;
    helix_h = tube_h - 6;
    union() {
        // central shaft
        cylinder(d = 3, h = helix_h);
        // helical fin built from rotated thin slabs
        for (i = [0 : n_steps - 1]) {
            z   = i * helix_h / n_steps;
            ang = 360 * z / helix_pitch;
            rotate([0, 0, ang])
                translate([0, -fin_t/2, z])
                    cube([helix_r, fin_t, helix_h/n_steps + 0.05]);
        }
    }
}

module f_tube() {
    difference() {
        cylinder(d = tube_od, h = tube_h);
        translate([0, 0, 1])
            cylinder(d = tube_id, h = tube_h + 0.1);
        // exit hole
        translate([0, 0, -0.1])
            cylinder(d = exit_d, h = 1.2);
    }
}

module f_assembly() {
    f_tube();
    translate([0, 0, 3]) f_helix();
    translate([0, 0, tube_h]) f_pinion();
    translate([0, 0, tube_h + pinion_h])
        cylinder(d = boss_d, h = boss_h);
}

f_assembly();

==== D_brush_comb.scad ====
// =====================================================================
// alternatives/D_brush_comb.scad — Brush / swab pickup + fixed comb
// knock-off (concept D).
// ---------------------------------------------------------------------
// A spindle-mounted disc carries a circular array of stiff bristle
// stand-offs (or a printed soft brush head); cohesive powder adheres
// between the bristles. A *fixed* printed comb on the bed strips the
// adhered powder into the receiving vial when the gantry sweeps the
// disc through it.
//
// Bristles are printed as thin pins (PETG / TPU) — at 0.2 mm layer
// height a 0.6 mm pin prints reliably. For a stiffer brush, replace
// the printed pins with cyanoacrylate-glued tufts of bottlebrush
// fibre.
// =====================================================================

$fa = 2; $fs = 0.3;

// --- Parameters (mm) -------------------------------------------------
boss_d        = 43;
boss_h        = 14;
boss_flat_w   = 6;
boss_flat_d   = 0.8;
disc_d        = 28;
disc_t        = 3;
n_bristles    = 24;
bristle_d     = 0.8;
bristle_h     = 6;
bristle_r     = 11;     // radial position of the bristle ring

// fixed comb on the bed
comb_l        = 30;
comb_w        = 8;
comb_h        = 14;
n_teeth       = 12;
tooth_w       = 0.9;
tooth_gap     = 1.2;

module d_brush_head() {
    // boss + disc
    translate([0, 0, disc_t])
        difference() {
            cylinder(d = boss_d, h = boss_h);
            for (sx = [-1, 1])
                translate([sx*(boss_d/2 - boss_flat_d),
                           -boss_flat_w/2, 2])
                    cube([boss_flat_d + 0.5, boss_flat_w, boss_h - 4]);
        }
    cylinder(d = disc_d, h = disc_t);

    // bristle ring
    for (i = [0 : n_bristles - 1])
        rotate([0, 0, 360 * i / n_bristles])
            translate([bristle_r, 0, -bristle_h])
                cylinder(d = bristle_d, h = bristle_h + 0.1);
}

module d_comb() {
    // bed-mounted comb. Sits on the bed offset from the powder bed; the
    // gantry rapids the brush through the comb and bristle-trapped
    // powder is combed off into the vial below.
    translate([0, 50, 0]) {
        difference() {
            translate([-comb_l/2, -comb_w/2, 0])
                cube([comb_l, comb_w, comb_h]);
            // teeth (slots top-side)
            for (i = [0 : n_teeth - 1])
                translate([-comb_l/2 + 2 + i*(tooth_w + tooth_gap),
                           -comb_w/2 - 0.1, comb_h - bristle_h - 0.5])
                    cube([tooth_gap, comb_w + 0.2, bristle_h + 0.6]);
            // M3 mount holes
            for (sx = [-1, 1])
                translate([sx*(comb_l/2 - 3), 0, -0.1])
                    cylinder(d = 3.4, h = comb_h + 0.2);
        }
    }
}

d_brush_head();
d_comb();


==== E_shaker.scad ====
// =====================================================================
// alternatives/E_shaker.scad — Salt-shaker oscillation (concept E).
// ---------------------------------------------------------------------
// Mounts on the spindle clamp. The cup base has a *patterned multi-hole
// floor* (like a salt shaker) instead of a fine mesh. The gantry shakes
// the cup in X-Y at ~5–20 Hz over the target vial; powder dispenses
// through the holes at a rate set by hole geometry × shake amplitude.
//
// Fully passive (gantry-as-actuator). One-piece print.
// =====================================================================

$fa = 2; $fs = 0.4;

// --- Parameters (mm) -------------------------------------------------
boss_d        = 43;
boss_h        = 14;
boss_flat_w   = 6;
boss_flat_d   = 0.8;
cup_id        = 22;
cup_wall      = 2.0;
cup_h         = 22;
floor_h       = 1.6;
hole_d        = 1.2;
n_rings       = 3;
holes_per_ring = [6, 12, 18];
ring_radii    = [3, 6.5, 9.5];

module e_shaker() {
    difference() {
        union() {
            cylinder(d = cup_id + 2*cup_wall, h = cup_h);
            translate([0, 0, cup_h])
                cylinder(d = boss_d, h = boss_h);
        }
        // wrench flats
        for (sx = [-1, 1])
            translate([sx*(boss_d/2 - boss_flat_d),
                       -boss_flat_w/2, cup_h + 2])
                cube([boss_flat_d + 0.5, boss_flat_w, boss_h - 4]);
        // hollow boss
        translate([0, 0, cup_h - 0.01])
            cylinder(d = cup_id - 4, h = boss_h + 0.1);
        // reservoir
        translate([0, 0, floor_h])
            cylinder(d = cup_id, h = cup_h);
        // hole pattern — concentric rings
        for (r_idx = [0 : n_rings - 1])
            for (i = [0 : holes_per_ring[r_idx] - 1]) {
                ang = 360 * i / holes_per_ring[r_idx];
                translate([ring_radii[r_idx]*cos(ang),
                           ring_radii[r_idx]*sin(ang), -0.1])
                    cylinder(d = hole_d, h = floor_h + 0.2);
            }
        // central hole
        translate([0, 0, -0.1])
            cylinder(d = hole_d, h = floor_h + 0.2);
    }
}

e_shaker();
